create table public.score_snapshots (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  cycle_id uuid not null references public.assessment_cycles(id) on delete cascade,  cycle_participant_id uuid not null references public.cycle_participants(id) on delete cascade,  competency_id uuid references public.competencies(id),  dimension_code text,  relationship_code text,  relationship_group text not null,  score_avg numeric,  response_count int not null default 0,  visibility_status text not null default 'visible'    check (visibility_status in ('visible','merged','hidden')),  generated_at timestamptz not null default now());create index on public.score_snapshots (tenant_id, cycle_id, cycle_participant_id);create table public.participant_result_profiles (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  cycle_id uuid not null references public.assessment_cycles(id) on delete cascade,  cycle_participant_id uuid not null references public.cycle_participants(id) on delete cascade,  overall_score numeric,  self_score numeric,  manager_score numeric,  peer_score numeric,  subordinate_score numeric,  blind_spot_count int not null default 0,  hidden_strength_count int not null default 0,  report_json jsonb,  generated_at timestamptz not null default now(),  unique (cycle_id, cycle_participant_id));